# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

properties([
    parameters([
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'URL to download the artifact from (S3, Artifactory, HTTP)'),
        string(name: 'ARTIFACT_NAME', defaultValue: 'application.jar', description: 'Name to save the artifact as'),
        choice(name: 'ENVIRONMENT', choices: ['staging', 'production'], description: 'Target environment'),
        string(name: 'DEPLOY_SERVERS', defaultValue: '', description: 'Comma-separated list of servers to deploy to'),
        string(name: 'DEPLOY_PATH', defaultValue: '/opt/application', description: 'Path on target servers to deploy artifact'),
        string(name: 'SERVICE_NAME', defaultValue: 'application', description: 'Service name to restart after deployment'),
        booleanParam(name: 'BACKUP_EXISTING', defaultValue: true, description: 'Backup existing artifact before deployment'),
        booleanParam(name: 'VERIFY_CHECKSUM', defaultValue: false, description: 'Verify artifact checksum'),
        string(name: 'CHECKSUM_URL', defaultValue: '', description: 'URL to checksum file (optional)'),
        string(name: 'CHECKSUM_VALUE', defaultValue: '', description: 'Expected checksum value (optional)'),
        choice(name: 'CHECKSUM_TYPE', choices: ['sha256', 'sha1', 'md5'], description: 'Checksum algorithm'),
        credentials(name: 'ARTIFACT_CREDENTIALS', description: 'Credentials for artifact download (optional)', required: false),
        credentials(name: 'SERVER_CREDENTIALS', description: 'SSH credentials for deployment servers', required: true, credentialType: 'com.cloudbees.plugins.credentials.impl.UsernamePasswordMultiBinding'),
        booleanParam(name: 'ROLLING_DEPLOYMENT', defaultValue: false, description: 'Deploy to servers one at a time'),
        string(name: 'HEALTH_CHECK_URL', defaultValue: '', description: 'Health check URL path (e.g., /health)'),
        string(name: 'HEALTH_CHECK_TIMEOUT', defaultValue: '60', description: 'Health check timeout in seconds'),
        booleanParam(name: 'DRY_RUN', defaultValue: false, description: 'Perform dry run without actual deployment')
    ])
])

pipeline {
    agent any
    
    environment {
        ARTIFACT_DIR = "${WORKSPACE}/artifacts"
        DEPLOYMENT_TIMESTAMP = sh(script: "date +%Y%m%d_%H%M%S", returnStdout: true).trim()
    }
    
    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.ARTIFACT_URL) {
                        error("ARTIFACT_URL parameter is required")
                    }
                    
                    if (!params.DEPLOY_SERVERS) {
                        error("DEPLOY_SERVERS parameter is required")
                    }
                    
                    if (params.VERIFY_CHECKSUM && !params.CHECKSUM_URL && !params.CHECKSUM_VALUE) {
                        error("CHECKSUM_URL or CHECKSUM_VALUE required when VERIFY_CHECKSUM is enabled")
                    }
                    
                    echo "Artifact URL: ${params.ARTIFACT_URL}"
                    echo "Target Environment: ${params.ENVIRONMENT}"
                    echo "Deploy Servers: ${params.DEPLOY_SERVERS}"
                    echo "Deploy Path: ${params.DEPLOY_PATH}"
                }
            }
        }
        
        stage('Prepare Workspace') {
            steps {
                script {
                    sh "rm -rf ${ARTIFACT_DIR}"
                    sh "mkdir -p ${ARTIFACT_DIR}"
                }
            }
        }
        
        stage('Download Artifact') {
            steps {
                script {
                    echo "Downloading artifact from: ${params.ARTIFACT_URL}"
                    
                    def downloadCommand = buildDownloadCommand(
                        params.ARTIFACT_URL,
                        "${ARTIFACT_DIR}/${params.ARTIFACT_NAME}",
                        params.ARTIFACT_CREDENTIALS
                    )
                    
                    def result = sh(script: downloadCommand, returnStatus: true)
                    
                    if (result != 0) {
                        error("Failed to download artifact from ${params.ARTIFACT_URL}")
                    }
                    
                    sh "ls -lh ${ARTIFACT_DIR}/${params.ARTIFACT_NAME}"
                    
                    def fileSize = sh(script: "stat -f%z ${ARTIFACT_DIR}/${params.ARTIFACT_NAME} 2>/dev/null || stat -c%s ${ARTIFACT_DIR}/${params.ARTIFACT_NAME}", returnStdout: true).trim()
                    echo "Downloaded artifact size: ${fileSize} bytes"
                }
            }
        }
        
        stage('Download Checksum') {
            when {
                expression { params.VERIFY_CHECKSUM && params.CHECKSUM_URL }
            }
            steps {
                script {
                    echo "Downloading checksum from: ${params.CHECKSUM_URL}"
                    
                    def downloadCommand = buildDownloadCommand(
                        params.CHECKSUM_URL,
                        "${ARTIFACT_DIR}/checksum.txt",
                        params.ARTIFACT_CREDENTIALS
                    )
                    
                    sh downloadCommand
                }
            }
        }
        
        stage('Verify Checksum') {
            when {
                expression { params.VERIFY_CHECKSUM }
            }
            steps {
                script {
                    def expectedChecksum = params.CHECKSUM_VALUE
                    
                    if (params.CHECKSUM_URL && !expectedChecksum) {
                        expectedChecksum = sh(script: "cat ${ARTIFACT_DIR}/checksum.txt | awk '{print \$1}'", returnStdout: true).trim()
                    }
                    
                    if (!expectedChecksum) {
                        error("No checksum value available for verification")
                    }
                    
                    echo "Verifying ${params.CHECKSUM_TYPE} checksum..."
                    
                    def actualChecksum = calculateChecksum("${ARTIFACT_DIR}/${params.ARTIFACT_NAME}", params.CHECKSUM_TYPE)
                    
                    echo "Expected: ${expectedChecksum}"
                    echo "Actual: ${actualChecksum}"
                    
                    if (actualChecksum.toLowerCase() != expectedChecksum.toLowerCase()) {
                        error("Checksum verification failed! Expected: ${expectedChecksum}, Got: ${actualChecksum}")
                    }
                    
                    echo "Checksum verification successful"
                }
            }
        }
        
        stage('Deploy to Servers') {
            steps {
                script {
                    def servers = params.DEPLOY_SERVERS.split(',').collect { it.trim() }
                    
                    echo "Deploying to ${servers.size()} server(s)"
                    
                    if (params.DRY_RUN) {
                        echo "DRY RUN MODE - No actual deployment will occur"
                    }
                    
                    if (params.ROLLING_DEPLOYMENT) {
                        echo "Performing rolling deployment..."
                        servers.each { server ->
                            deployToServer(server)
                        }
                    } else {
                        echo "Performing parallel deployment..."
                        def deploymentSteps = [:]
                        servers.each { server ->
                            deploymentSteps[server] = {
                                deployToServer(server)
                            }
                        }
                        parallel deploymentSteps
                    }
                }
            }
        }
        
        stage('Verify Deployment') {
            when {
                expression { params.HEALTH_CHECK_URL && !params.DRY_RUN }
            }
            steps {
                script {
                    def servers = params.DEPLOY_SERVERS.split(',').collect { it.trim() }
                    
                    echo "Verifying deployment health checks..."
                    
                    servers.each { server ->
                        verifyServerHealth(server)
                    }
                    
                    echo "All servers passed health checks"
                }
            }
        }
    }
    
    post {
        success {
            script {
                echo "Deployment completed successfully"
                echo "Artifact: ${params.ARTIFACT_NAME}"
                echo "Environment: ${params.ENVIRONMENT}"
                echo "Servers: ${params.DEPLOY_SERVERS}"
                echo "Timestamp: ${DEPLOYMENT_TIMESTAMP}"
            }
        }
        failure {
            script {
                echo "Deployment failed!"
                echo "Check logs for details"
            }
        }
        always {
            script {
                sh "rm -rf ${ARTIFACT_DIR}"
            }
        }
    }
}

def buildDownloadCommand(url, destination, credentialsId) {
    def command = ""
    
    if (url.startsWith('s3://')) {
        command = "aws s3 cp '${url}' '${destination}'"
        if (credentialsId) {
            withCredentials([usernamePassword(credentialsId: credentialsId, usernameVariable: 'AWS_ACCESS_KEY_ID', passwordVariable: 'AWS_SECRET_ACCESS_KEY')]) {
                command = "AWS_ACCESS_KEY_ID='${AWS_ACCESS_KEY_ID}' AWS_SECRET_ACCESS_KEY='${AWS_SECRET_ACCESS_KEY}' ${command}"
            }
        }
    } else if (url.contains('artifactory')) {
        if (credentialsId) {
            command = """
                withCredentials([usernamePassword(credentialsId: '${credentialsId}', usernameVariable: 'USER', passwordVariable: 'PASS')]) {
                    sh "curl -u '\${USER}:\${PASS}' -L -o '${destination}' '${url}'"
                }
            """
            return command
        } else {
            command = "curl -L -o '${destination}' '${url}'"
        }
    } else {
        if (credentialsId) {
            command = """
                withCredentials([usernamePassword(credentialsId: '${credentialsId}', usernameVariable: 'USER', passwordVariable: 'PASS')]) {
                    sh "curl -u '\${USER}:\${PASS}' -L -o '${destination}' '${url}'"
                }
            """
            return command
        } else {
            command = "curl -L -o '${destination}' '${url}'"
        }
    }
    
    return command
}

def calculateChecksum(filePath, algorithm) {
    def command = ""
    
    switch(algorithm) {
        case 'sha256':
            command = "shasum -a 256 '${filePath}' | awk '{print \$1}'"
            break
        case 'sha1':
            command = "shasum -a 1 '${filePath}' | awk '{print \$1}'"
            break
        case 'md5':
            command = "md5sum '${filePath}' 2>/dev/null | awk '{print \$1}' || md5 -q '${filePath}'"
            break
        default:
            error("Unsupported checksum algorithm: ${algorithm}")
    }
    
    return sh(script: command, returnStdout: true).trim()
}

def deployToServer(server) {
    echo "Deploying to server: ${server}"
    
    withCredentials([usernamePassword(credentialsId: params.SERVER_CREDENTIALS, usernameVariable: 'SSH_USER', passwordVariable: 'SSH_PASS')]) {
        
        if (params.DRY_RUN) {
            echo "[DRY RUN] Would deploy ${params.ARTIFACT_NAME} to ${server}:${params.DEPLOY_PATH}"
            echo "[DRY RUN] Would restart service: ${params.SERVICE_NAME}"
            return
        }
        
        if (params.BACKUP_EXISTING) {
            echo "Backing up existing artifact on ${server}..."
            sh """
                sshpass -p '${SSH_PASS}' ssh -o StrictHostKeyChecking=no ${SSH_USER}@${server} \
                "if [ -f ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME} ]; then \
                    cp ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME} ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}.backup.${DEPLOYMENT_TIMESTAMP}; \
                fi"
            """
        }
        
        echo "Creating deployment directory on ${server}..."
        sh """
            sshpass -p '${SSH_PASS}' ssh -o StrictHostKeyChecking=no ${SSH_USER}@${server} \
            "mkdir -p ${params.DEPLOY_PATH}"
        """
        
        echo "Copying artifact to ${server}..."
        sh """
            sshpass -p '${SSH_PASS}' scp -o StrictHostKeyChecking=no \
            ${ARTIFACT_DIR}/${params.ARTIFACT_NAME} \
            ${SSH_USER}@${server}:${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}
        """
        
        echo "Setting permissions on ${server}..."
        sh """
            sshpass -p '${SSH_PASS}' ssh -o StrictHostKeyChecking=no ${SSH_USER}@${server} \
            "chmod 755 ${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}"
        """
        
        if (params.SERVICE_NAME) {
            echo "Restarting service ${params.SERVICE_NAME} on ${server}..."
            sh """
                sshpass -p '${SSH_PASS}' ssh -o StrictHostKeyChecking=no ${SSH_USER}@${server} \
                "sudo systemctl restart ${params.SERVICE_NAME} || sudo service ${params.SERVICE_NAME} restart"
            """
            
            sleep(time: 5, unit: 'SECONDS')
            
            echo "Checking service status on ${server}..."
            sh """
                sshpass -p '${SSH_PASS}' ssh -o StrictHostKeyChecking=no ${SSH_USER}@${server} \
                "sudo systemctl is-active ${params.SERVICE_NAME} || sudo service ${params.SERVICE_NAME} status"
            """
        }
        
        echo "Deployment to ${server} completed successfully"
    }
}

def verifyServerHealth(server) {
    echo "Checking health of ${server}..."
    
    def healthUrl = "http://${server}${params.HEALTH_CHECK_URL}"
    def timeout = params.HEALTH_CHECK_TIMEOUT.toInteger()
    def interval = 5
    def elapsed = 0
    
    while (elapsed < timeout) {
        try {
            def response = sh(script: "curl -s -o /dev/null -w '%{http_code}' ${healthUrl}", returnStdout: true).trim()
            
            if (response == '200') {
                echo "Health check passed for ${server} (HTTP ${response})"
                return
            } else {
                echo "Health check returned HTTP ${response}, retrying..."
            }
        } catch (Exception e) {
            echo "Health check failed: ${e.message}, retrying..."
        }
        
        sleep(time: interval, unit: 'SECONDS')
        elapsed += interval
    }
    
    error("Health check failed for ${server} after ${timeout} seconds")
}